arguments.new_str:
using Microsoft.ML;
using Microsoft.ML.Data;

var builder = WebApplication.CreateBuilder(args);

// Register the pooled prediction engine (thread-safe for web use)
var mlContext = new MLContext(seed: 42);
var dataPath = Path.Combine(AppContext.BaseDirectory, "Data", "customers.csv");
var dataView = mlContext.Data.LoadFromTextFile<ChurnInput>(dataPath, hasHeader: true, separatorChar: ',');
var split = mlContext.Data.TrainTestSplit(dataView, testFraction: 0.2);

var pipeline = mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", nameof(ChurnInput.Region))
    .Append(mlContext.Transforms.NormalizeMinMax(nameof(ChurnInput.Age)))
    .Append(mlContext.Transforms.NormalizeMinMax(nameof(ChurnInput.Income)))
    .Append(mlContext.Transforms.NormalizeMinMax(nameof(ChurnInput.PurchaseHistory)))
    .Append(mlContext.Transforms.Concatenate("Features",
        nameof(ChurnInput.Age), nameof(ChurnInput.Income), "RegionEncoded", nameof(ChurnInput.PurchaseHistory)))
    .Append(mlContext.BinaryClassification.Trainers.SdcaLogisticRegression(
        labelColumnName: nameof(ChurnInput.Churned), featureColumnName: "Features"));

var model = pipeline.Fit(split.TrainSet);

// Evaluate on test set
var predictions = model.Transform(split.TestSet);
var metrics = mlContext.BinaryClassification.Evaluate(predictions, labelColumnName: nameof(ChurnInput.Churned));
Console.WriteLine($"AUC: {metrics.AreaUnderRocCurve:F4}, F1: {metrics.F1Score:F4}, Accuracy: {metrics.Accuracy:F4}");

builder.Services.AddPredictionEnginePool<ChurnInput, ChurnOutput>()
    .FromModel(model, mlContext);

var app = builder.Build();

app.MapPost("/predict", (PredictionEnginePool<ChurnInput, ChurnOutput> pool, ChurnInput input) =>
{
    var result = pool.Predict(input);
    return Results.Ok(new { WillChurn = result.PredictedLabel, Probability = result.Probability });
});

app.Run();

public class ChurnInput
{
    [LoadColumn(0)] public float Age { get; set; }
    [LoadColumn(1)] public float Income { get; set; }
    [LoadColumn(2)] public string Region { get; set; } = "";
    [LoadColumn(3)] public float PurchaseHistory { get; set; }
    [LoadColumn(4), ColumnName("Churned")]
    public bool Churned { get; set; }
}

public class ChurnOutput
{
    [ColumnName("PredictedLabel")]
    public bool PredictedLabel { get; set; }
    public float Probability { get; set; }
}

